import React, { useEffect, useState } from 'react';
import axios from 'axios';

const AdminDashboard = () => {
  const [stats, setStats] = useState({});

  useEffect(() => {
    const fetchStats = async () => {
      const token = localStorage.getItem('token');
      const res = await axios.get('http://localhost:5000/api/reports', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setStats(res.data);
    };
    fetchStats();
  }, []);

  return (
    <div>
      <h1>Admin Dashboard</h1>
      <p>Total Books: {stats.totalBooks}</p>
      <p>Total Members: {stats.totalMembers}</p>
      <p>Issued Books: {stats.issuedBooks}</p>
      <p>Overdue Books: {stats.overdueBooks}</p>
      <a href="/admin/books">Manage Books</a> | <a href="/admin/members">Manage Members</a> | <a href="/admin/issue-return">Issue/Return</a> | <a href="/admin/reports">Reports</a>
    </div>
  );
};

export default AdminDashboard;
